  ('pukao-d1056197-moex-00247', 'pukao-d1056197', 'pukao-d1056197-moex-110-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '依國家賠償法之規定，關於國家賠償請求權之行使，下列敘述何者正確？', '["請求權人限於權利受損害之自然人，不包括法人", "因公務員行為所生之國家賠償責任，賠償義務人為從事該行為之公務員", "請求權人如未經協議程序，即向法院提起國家賠償訴訟，該訴訟不合法", "國家賠償之訴訟，除依國家賠償法之規定外，應準用行政訴訟法之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:49+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00248', 'pukao-d1056197', 'pukao-d1056197-moex-110-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '甲之三合院古厝，長期出租他人作為廠房使用。嗣主管機關依法將其列為暫定古蹟，但因承租人之營 運可能破壞古蹟，致甲不得繼續出租。甲得基於下列何者，請求主管機關彌補其租金收益損失？', '["公法上不當得利返還請求權", "損失補償請求權", "國家賠償請求權", "公法上無因管理之管理費用請求權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:49+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00249', 'pukao-d1056197', 'pukao-d1056197-moex-110-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '關於徵收補償之敘述，下列何者正確？', '["須為合法公權力措施", "適用第一次權利保護優先原則", "當事人無須構成特別犧牲", "原公權力措施得預見其附帶違法侵害效果"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:49+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00250', 'pukao-d1056197', 'pukao-d1056197-moex-110-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '關於國家賠償法第3條公共設施之敘述，下列何者錯誤？', '["縱使尚未驗收合格之公共設施，如已開放公眾使用，仍有國家賠償法之適用", "公共設施之開放使用係屬行政機關事實行為", "私人所有之公共設施，亦有國家賠償法之適用", "公共設施設置地點之選定，屬公權力行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:49+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00001', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-6948958a', 'sub-pukao-d592fc58-01', NULL, 'single_choice', '機會成本會沿著生產可能曲線增加，是因為：', '["資源在經濟活動中的邊際生產力遞減", "有越來越多的需求被滿足", "為生產更多的某一種商品，必須減少另一商品生產的數量", "生產需要時間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00002', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-6948958a', 'sub-pukao-d592fc58-01', NULL, 'single_choice', '相對於乙國，甲國生產某商品具有比較利益，則下列何者正確？', '["甲國生產該商品的各種要素投入一定比較少", "乙國生產該產品的各種要素投入一定比較多", "甲國生產該產品的機會成本一定比較低", "乙國生產該產品的機會成本一定比較低"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
